// 입력 파싱: 공고ID 추출 (JSON + text/plain 모두 지원)
const raw = $input.first().json;
let announcementId = '';

// JSON body에서 직접
if (raw.body && raw.body.announcementId) {
  announcementId = raw.body.announcementId;
} else if (raw.announcementId) {
  announcementId = raw.announcementId;
} else if (raw.id) {
  announcementId = raw.id;
} else if (typeof raw.body === 'string') {
  // text/plain으로 온 경우 JSON 파싱 시도
  try {
    const parsed = JSON.parse(raw.body);
    announcementId = parsed.announcementId || parsed.id || '';
  } catch(e) {
    // 숫자만 들어온 경우
    announcementId = raw.body.trim();
  }
}

if (!announcementId) {
  throw new Error('announcementId가 필요합니다');
}

return [{ json: { announcementId: Number(announcementId) || announcementId } }];

// 공고 데이터 추출 + 첨부파일URL 파싱
const records = $input.first().json.list || [];
if (records.length === 0) {
  throw new Error('공고를 찾을 수 없습니다');
}

const record = records[0];
let attachUrls = [];
try {
  if (record['첨부파일URL']) {
    attachUrls = JSON.parse(record['첨부파일URL']);
  }
} catch(e) {
  if (typeof record['첨부파일URL'] === 'string') {
    attachUrls = [record['첨부파일URL']];
  }
}

const hwpxUrls = attachUrls.filter(u => /\.hwpx/i.test(u) || u.includes('atchFileId'));

return [{ json: {
  id: record.Id,
  사업명: record['지원사업이름'] || '',
  소관기관: record['소관기관'] || '',
  지원내용: record['추천이유_상세'] || record['적합이유'] || '',
  예상지원규모: record['예상지원규모'] || '',
  신청Link: record['신청Link'] || '',
  첨부파일URLs: hwpxUrls,
  hasHWPX: hwpxUrls.length > 0,
  필요서류: record['필요서류_예측'] || record['필요서류_실제'] || '',
} }];

// 회사 프로파일 + 공고 URL → fill-by-url 요청 body 생성

const profileData = $input.first().json;
const profileRecords = profileData.list || [profileData];
const profile = profileRecords[0] || {};

let announcement;
try {
  announcement = $('Code 공고 파싱').first().json;
} catch(e) {
  announcement = { 사업명: '알수없음', 소관기관: '', 첨부파일URLs: [] };
}

const hwpxUrl = (announcement.첨부파일URLs || [])[0] || '';

const fieldMap = {
  '기업명': profile['회사명'] || '프레스코21',
  '회사명': profile['회사명'] || '프레스코21',
  '상호': profile['회사명'] || '프레스코21',
  '대표자명': profile['대표자명'] || '이진선',
  '대표자': profile['대표자명'] || '이진선',
  '대표자 명': profile['대표자명'] || '이진선',
  '사업자등록번호': profile['사업자번호'] || '215-05-52221',
  '사업장 주소': profile['소재지'] || '서울특별시 송파구 가락동',
  '주소': profile['소재지'] || '서울특별시 송파구 가락동',
  '업태': profile['업태'] || '도소매업',
  '업종': profile['종목'] || '꽃 및 생활소품',
  '종목': profile['종목'] || '꽃 및 생활소품',
  '상시근로자': profile['상시근로자수'] || '8',
  '직원수': profile['상시근로자수'] || '8',
  '임직원 수': profile['상시근로자수'] || '8',
  '이메일': profile['이메일'] || 'pressco21@foreverlove.co.kr',
  '연락처': profile['전화번호'] || '',
  '전화번호': profile['전화번호'] || '',
  '홈페이지': profile['웹사이트'] || 'https://foreverlove.co.kr',
  '홈페이지 주소': profile['웹사이트'] || 'https://foreverlove.co.kr',
};

// 회사 정보를 간결하게 정리
const companyInfo = [
  (profile['회사명'] || '프레스코21') + ' | 대표: ' + (profile['대표자명'] || '이진선') + '(1961년생,여성)',
  '사업자: ' + (profile['사업자번호'] || '215-05-52221'),
  '업종: ' + (profile['업태'] || '도소매업') + '/' + (profile['종목'] || '꽃 및 생활소품,무역'),
  '소재지: ' + (profile['소재지'] || '서울특별시 송파구 가락동 98-2'),
  '직원 ' + (profile['상시근로자수'] || '8') + '명(여성5명/남성3명, 청년2명/청년외6명)',
  '연매출 약 ' + (profile['연간매출액'] || '10억원') + ' | 1999년 12월 창업(26년)',
  '여성기업인증, 소기업확인서 보유',
  '담당자: 장지호(경영기획팀장) 02-407-5755 pressco21@foreverlove.co.kr',
  '자사몰 foreverlove.co.kr + 스마트스토어/쿠팡/11번가 (5개 채널)',
  '유튜브 2,160구독 467영상 | 인스타그램 1,683팔로워',
  '주요사업: 압화/드라이플라워/프리저브드플라워/레진공예/하바리움 온라인 도소매',
  '2026년 파트너클래스 교육플랫폼 론칭 | n8n 업무자동화/AI챗봇 자체 구축',
  '시차출퇴근제 운영(디자인기획팀3명) | 재택근무 주1회 시행',
  '육아휴직 2025년 여성1명(복직완료) | 출산휴가 2025년 여성1명',
].join('\n');

const requestBody = {
  announcement_name: announcement.사업명 || '',
  announcement_id: announcement.id || 0,
  hwpx_url: hwpxUrl,
  auto_fill: true,
  company_info: companyInfo,
  announcement_info: (announcement.사업명 || '') + ' - ' + (announcement.지원내용 || ''),
  replacements: {},  // AI auto_fill이 전부 처리
  return_type: 'report'
};

return [{ json: {
  requestBody,
  hwpxUrl,
  announcement,
} }];

// fill-by-url 응답에서 리포트 생성 + 다운로드 링크
const result = $input.first().json;
const mappingData = $('Code 매핑 생성').first().json;
const announcement = mappingData.announcement || {};

const isSuccess = result.success === true;
const mappedCount = result.mapped_count || 0;
const totalFields = result.total_form_fields || 0;
const folder = result.folder || '';
const downloadUrl = result.download_url || '';

let msg;
if (isSuccess) {
  const filledLabels = (result.fill_report || {}).table_filled || [];
  const labelList = filledLabels.map(f => f.label).join(', ');
  msg = '<b>HWPX 서식 자동 채움 완료</b>\n\n' +
    '<b>공고:</b> ' + (announcement.사업명 || '') + '\n' +
    '<b>기관:</b> ' + (announcement.소관기관 || '') + '\n' +
    '<b>매핑:</b> ' + mappedCount + '/' + totalFields + '개 필드 자동 채움\n' +
    '<b>채운 항목:</b> ' + (labelList || '없음') + '\n' +
    '<b>폴더:</b> ' + folder + '\n\n' +
    '서술형 항목은 반드시 검토 후 수정하세요';
} else {
  const errorMsg = result.error || '';
  msg = '<b>HWPX 서식 채움 실패</b>\n\n' +
    '<b>공고:</b> ' + (announcement.사업명 || '') + '\n' +
    '<b>오류:</b> ' + (typeof errorMsg === 'string' ? errorMsg : JSON.stringify(errorMsg).substring(0, 200));
}

return [{ json: { message: msg, chatId: '7713811206' } }];

